1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH
9	int eval_err;
10	
11	// Apply a binary op to two scalars
12	int eval_binop_scalar(int op, int a, int b) {
13	    if (op == TOK_PLUS)       return a + b;
14	    if (op == TOK_MINUS)      return a - b;
15	    if (op == TOK_STAR)       return a * b;
16	    if (op == TOK_SLASH) {
17	        if (b == 0) { eval_err = 1; return 0; }
18	        return a / b;
19	    }
20	    eval_err = 1;
21	    return 0;
22	}
23	
24	// Evaluate AST node, return heap index of result array.
25	// On error, sets eval_err and returns -1.
26	int eval(int n) {
27	    if (eval_err) return -1;
28	    if (n < 0 || n >= node_count) {
29	        eval_err = 1;
30	        return -1;
31	    }
32	
33	    int ty = node_type[n];
34	
35	    if (ty == NODE_NUM) {
36	        int r = arr_scalar(node_val[n]);
37	        if (r < 0) { eval_err = 1; return -1; }
38	        return r;
39	    }
40	
41	    if (ty == NODE_VEC) {
42	        return node_val[n];
43	    }
44	
45	    if (ty == NODE_IDENT) {
46	        int idx = node_val[n];
47	        if (!sym_set_flag[idx]) {
48	            eval_err = 2;
49	            return -1;
50	        }
51	        return sym_val[idx];
52	    }
53	
54	    if (ty == NODE_ASSIGN) {
55	        int idx = node_val[n];
56	        int v = eval(node_right[n]);
57	        if (eval_err) return -1;
58	        sym_val[idx] = v;
59	        sym_set_flag[idx] = 1;
60	        return v;
61	    }
62	
63	    if (ty == NODE_NEG) {
64	        int v = eval(node_right[n]);
65	        if (eval_err) return -1;
66	        int rk = arr_rank(v);
67	        if (rk == 0) {
68	            int r = arr_scalar(0 - arr_get(v, 0));
69	            if (r < 0) { eval_err = 1; return -1; }
70	            return r;
71	        }
72	        // Negate each element of vector
73	        int sz = arr_size(v);
74	        int r = arr_vector(sz);
75	        if (r < 0) { eval_err = 1; return -1; }
76	        int i = 0;
77	        while (i < sz) {
78	            arr_set(r, i, 0 - arr_get(v, i));
79	            i++;
80	        }
81	        return r;
82	    }
83	
84	    if (ty == NODE_MONAD) {
85	        int v = eval(node_right[n]);
86	        if (eval_err) return -1;
87	        int res_id = node_val[n];
88	
89	        if (res_id == RES_IOTA) {
90	            // iota N: generate vector 0 1 2 ... N-1
91	            if (arr_rank(v) != 0) { eval_err = 3; return -1; }
92	            int count = arr_get(v, 0);
93	            if (count < 0) { eval_err = 1; return -1; }
94	            int r = arr_vector(count);
95	            if (r < 0) { eval_err = 1; return -1; }
96	            int i = 0;
97	            while (i < count) {
98	                arr_set(r, i, i);
99	                i++;
100	            }
101	            return r;
102	        }
103	
104	        // Unknown monadic function
105	        eval_err = 1;
106	        return -1;
107	    }
108	
109	    if (ty == NODE_BINOP) {
110	        int lv = eval(node_left[n]);
111	        if (eval_err) return -1;
112	        int rv = eval(node_right[n]);
113	        if (eval_err) return -1;
114	
115	        int lrk = arr_rank(lv);
116	        int rrk = arr_rank(rv);
117	        int op = node_val[n];
118	
119	        // Scalar op scalar
120	        if (lrk == 0 && rrk == 0) {
121	            int result = eval_binop_scalar(op, arr_get(lv, 0), arr_get(rv, 0));
122	            if (eval_err) return -1;
123	            int r = arr_scalar(result);
124	            if (r < 0) { eval_err = 1; return -1; }
125	            return r;
126	        }
127	
128	        // Vector op vector: must match length
129	        if (lrk == 1 && rrk == 1) {
130	            int lsz = arr_size(lv);
131	            int rsz = arr_size(rv);
132	            if (lsz != rsz) { eval_err = 3; return -1; }
133	            int r = arr_vector(lsz);
134	            if (r < 0) { eval_err = 1; return -1; }
135	            int i = 0;
136	            while (i < lsz) {
137	                int val = eval_binop_scalar(op, arr_get(lv, i), arr_get(rv, i));
138	                if (eval_err) return -1;
139	                arr_set(r, i, val);
140	                i++;
141	            }
142	            return r;
143	        }
144	
145	        // Scalar op vector
146	        if (lrk == 0 && rrk == 1) {
147	            int la = arr_get(lv, 0);
148	            int rsz = arr_size(rv);
149	            int r = arr_vector(rsz);
150	            if (r < 0) { eval_err = 1; return -1; }
151	            int i = 0;
152	            while (i < rsz) {
153	                int val = eval_binop_scalar(op, la, arr_get(rv, i));
154	                if (eval_err) return -1;
155	                arr_set(r, i, val);
156	                i++;
157	            }
158	            return r;
159	        }
160	
161	        // Vector op scalar
162	        if (lrk == 1 && rrk == 0) {
163	            int ra = arr_get(rv, 0);
164	            int lsz = arr_size(lv);
165	            int r = arr_vector(lsz);
166	            if (r < 0) { eval_err = 1; return -1; }
167	            int i = 0;
168	            while (i < lsz) {
169	                int val = eval_binop_scalar(op, arr_get(lv, i), ra);
170	                if (eval_err) return -1;
171	                arr_set(r, i, val);
172	                i++;
173	            }
174	            return r;
175	        }
176	
177	        // Unsupported rank combination
178	        eval_err = 1;
179	        return -1;
180	    }
181	
182	    eval_err = 1;
183	    return -1;
